"use client";

import * as ScrollAreaPrimitive from "@radix-ui/react-scroll-area";
import type * as React from "react";
import { cn } from "@/lib/utils";

/**
 * Brand-styled scroll surface — wraps Radix's headless scroll-area
 * primitive (the same one shadcn ships). Behaviour:
 *
 *   - Scrollbars are **hidden** by default and reveal on hover
 *     anywhere over the scroll surface OR while the visitor is
 *     actively scrolling (Radix's default).
 *   - Thumb uses the muted foreground token at ~30% so it reads as
 *     chrome, not content — same visual weight as the widget's
 *     secondary text.
 *   - Track is transparent so existing surface backgrounds (bubble
 *     elevated, gradient hero, etc.) carry through.
 *
 * Usage:
 *
 *   <ScrollArea className="flex-1">
 *     <div>... scrollable content ...</div>
 *   </ScrollArea>
 *
 * Pass `flex-1` (or similar) on the ScrollArea root to make it
 * inherit available height from its parent flex column.
 */
interface ScrollAreaProps extends React.ComponentProps<typeof ScrollAreaPrimitive.Root> {
  /** Ref forwarded to the inner Viewport — the element that actually
   *  scrolls. Use this when callers need `scrollTo` / `scrollHeight`
   *  (eg. auto-scrolling a chat list to the bottom). The Root's
   *  default ref isn't useful for that because it just points at the
   *  outer wrapper. */
  viewportRef?: React.Ref<HTMLDivElement>;
}

function ScrollArea({
  className,
  viewportRef,
  children,
  // The Radix Root doesn't scroll — its inner Viewport does. Pull
  // `onScroll` out of the spread so it lands on the Viewport, where
  // the scroll event actually fires. Callers that pass `onScroll`
  // (infinite-scroll triggers, "near the bottom" load-more handlers)
  // depend on this.
  onScroll,
  ...props
}: ScrollAreaProps) {
  return (
    <ScrollAreaPrimitive.Root
      data-slot="scroll-area"
      // `overflow-hidden` clips the viewport to the Root's box —
      // without it, content inside the viewport pushes the Root
      // taller than its `flex-1` slot, which is what was making
      // the messages composer disappear and Help / News content
      // overflow.
      // `min-h-0 min-w-0` lets the Root actually shrink inside a
      // flex parent (flex children default to `min-height: auto`,
      // which prevents the constraint from kicking in).
      className={cn("relative min-h-0 min-w-0 overflow-hidden", className)}
      {...props}
    >
      <ScrollAreaPrimitive.Viewport
        ref={viewportRef}
        data-slot="scroll-area-viewport"
        onScroll={onScroll}
        className={cn(
          "h-full w-full rounded-[inherit]",
          // Radix wraps children in a `<div style="min-width:100%;
          // display:table">` for horizontal-overflow support. That
          // `display:table` semantics let inner content GROW the
          // table past 100% width if a child has an intrinsic
          // size (which broke widget cards on 375 px viewports — a
          // 400 px-natural card overflowed the panel). Force the
          // inner wrapper to `block` + clamp to `100%` width so
          // children honour the parent's width budget instead.
          "[&>div]:!block [&>div]:!w-full [&>div]:!max-w-full",
          "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary/40",
        )}
      >
        {children}
      </ScrollAreaPrimitive.Viewport>
      <ScrollBar />
      <ScrollAreaPrimitive.Corner />
    </ScrollAreaPrimitive.Root>
  );
}

function ScrollBar({
  className,
  orientation = "vertical",
  ...props
}: React.ComponentProps<typeof ScrollAreaPrimitive.ScrollAreaScrollbar>) {
  return (
    <ScrollAreaPrimitive.ScrollAreaScrollbar
      data-slot="scroll-area-scrollbar"
      orientation={orientation}
      // Radix sets `data-state="visible|hidden"` based on scrolling
      // activity. We fade with `opacity` so the bar can also be
      // reveal-on-hover via the parent's group/hover state.
      className={cn(
        "flex touch-none select-none transition-opacity duration-150",
        // Default: invisible. Visible whenever Radix marks the bar as
        // visible (active scrolling) OR the visitor is hovering the
        // scroll area.
        "opacity-0 data-[state=visible]:opacity-100",
        "hover:opacity-100",
        orientation === "vertical" && "h-full w-1.5 border-l border-l-transparent p-px",
        orientation === "horizontal" && "h-1.5 flex-col border-t border-t-transparent p-px",
        className,
      )}
      {...props}
    >
      <ScrollAreaPrimitive.ScrollAreaThumb
        data-slot="scroll-area-thumb"
        className={cn(
          "relative flex-1 rounded-full",
          // Subtle muted thumb — same colour as helper text. Reads as
          // chrome on every widget surface (light bubble, primary
          // bubble, gradient hero).
          "bg-wx-fg-muted/40 hover:bg-wx-fg-muted/60 transition-colors",
        )}
      />
    </ScrollAreaPrimitive.ScrollAreaScrollbar>
  );
}

export { ScrollArea, ScrollBar };
