import * as React from "react";
import { cn } from "@/lib/utils";

/**
 * Surface primitive. Two visual heights:
 *
 *   - `Card`        — default, sits on `--wx-bg`, painted in
 *                     `--wx-bg-elevated`. The Home tab's stacked
 *                     blocks use this.
 *   - `CardNested`  — for surfaces that live INSIDE another card
 *                     (e.g. an inline action chip on the recent
 *                     message card). Uses `--wx-bg-elevated-2`.
 *
 * Padding stays caller-controlled — different surfaces (button-as-
 * card vs. content card vs. media card) want different paddings.
 */
export const Card = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn("rounded-wx-lg bg-wx-bg-elevated text-wx-fg", className)}
      {...props}
    />
  ),
);
Card.displayName = "Card";

export const CardNested = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn("rounded-wx bg-wx-bg-elevated-2 text-wx-fg", className)}
      {...props}
    />
  ),
);
CardNested.displayName = "CardNested";

