/**
 * Demo author identities, shared by help articles + news posts. Proper
 * names + seeded face avatars (pravatar) so demo content reads like
 * real, attributed writing. Names aren't translated — like "Gaia".
 *
 * Both surfaces support MULTIPLE authors: a struct lists `authorIds`,
 * and the builder maps them to these records via `authorsFor`.
 */
export interface DemoAuthor {
  _id: string;
  name: string;
  photo: { url: string };
}

export const DEMO_AUTHORS = {
  maya: {
    _id: "demo-author-maya",
    name: "Maya Chen",
    photo: { url: "https://i.pravatar.cc/96?img=47" },
  },
  leo: {
    _id: "demo-author-leo",
    name: "Leo Martins",
    photo: { url: "https://i.pravatar.cc/96?img=13" },
  },
  ira: {
    _id: "demo-author-ira",
    name: "Ira Kovalenko",
    photo: { url: "https://i.pravatar.cc/96?img=32" },
  },
  sam: {
    _id: "demo-author-sam",
    name: "Sam Okafor",
    photo: { url: "https://i.pravatar.cc/96?img=68" },
  },
} as const satisfies Record<string, DemoAuthor>;

export type DemoAuthorKey = keyof typeof DEMO_AUTHORS;

/** Resolve a list of author keys to their full records. */
export function authorsFor(keys: readonly DemoAuthorKey[]): DemoAuthor[] {
  return keys.map((key) => DEMO_AUTHORS[key]);
}
