import type {
  InjectableWidgetConfig,
  PrechatFieldKind,
  WidgetConfig,
  WidgetPrechatForm,
} from "./widget-config";

/**
 * The widget's REST surface area is **one endpoint**: the loader-script
 * bootstrap call to `GET /api/web/config/:publicKey`. Everything else
 * (messages, news, help, signals, upload, history) goes through the
 * visitor-facing GraphQL resolver wired in Day 1c.
 *
 * Why config stays REST: the loader script that injects this iframe
 * does NOT bundle Apollo — keeping config as a simple GET means the
 * loader can pre-fetch it before the iframe mounts, avoiding a
 * round-trip of empty-state paint during cold loads.
 */

/** Plain-localhost HTTP fallback — Storybook, headless CI, anything
 *  served on `http://localhost` where the BE also runs on HTTP. */
const DEFAULT_API_BASE_HTTP = "http://localhost:3001";

/** Cert-backed HTTPS endpoint the BE exposes locally — used when the
 *  host page is the dashboard at `https://local.app.wexio.io:3000`
 *  (browser blocks mixed http→https; the matching `local.api.wexio.io`
 *  cert avoids that and satisfies CORS). */
const DEFAULT_API_BASE_HTTPS_LOCAL = "https://local.api.wexio.io:3443";

/**
 * Resolve the BE base URL the widget should hit.
 *
 * Order of precedence:
 *   1. **`NEXT_PUBLIC_WEXIO_API_URL`** — explicit override, wins. Set
 *      this in `web-widget/.env.local` to point at a custom BE.
 *   2. **Same-protocol same-domain auto-detect** — when the host page
 *      is on `https://*.wexio.io`, route to the matching
 *      `api.<rest>.wexio.io` so dev (`local.api.wexio.io:3443`) and
 *      prod (`api.wexio.io`) both work without env config.
 *   3. **Plain-localhost fallback** — `http://localhost:3001` for
 *      Storybook / CI / non-cert local setups.
 *
 * SSR-safe: reads `window.location` only in the browser; falls back
 * to the http default during SSR (which is fine — the widget never
 * fetches during SSR).
 */
export function apiBase(): string {
  const override = process.env.NEXT_PUBLIC_WEXIO_API_URL;
  if (override) return override;

  if (typeof window !== "undefined") {
    const { protocol, hostname } = window.location;

    // Local dashboard (`local.app.wexio.io`) → local BE
    // (`local.api.wexio.io:3443`). The BE serves a matching cert so
    // CORS preflight + secure-context constraints all line up.
    if (protocol === "https:" && /^local\.[a-z-]+\.wexio\.io$/i.test(hostname)) {
      return DEFAULT_API_BASE_HTTPS_LOCAL;
    }

    // Production / staging / PR dashboards on any `.wexio.io`
    // subdomain → derive the `api.` sibling by swapping the `app` /
    // `templates` segment for `api`. e.g.
    //   `app.wexio.io`         → `api.wexio.io`
    //   `staging.app.wexio.io` → `staging.api.wexio.io`
    //   `pr-123.app.wexio.io`  → `pr-123.api.wexio.io`
    if (protocol === "https:" && /\.wexio\.io$/i.test(hostname)) {
      const apiHost = hostname
        // `app.wexio.io` / `templates.wexio.io` → `api.wexio.io`.
        .replace(/^(app|templates)\./i, "api.")
        // `<env>.app.wexio.io` / `<env>.templates.wexio.io` →
        // `<env>.api.wexio.io`.
        .replace(/\.(app|templates)\./i, ".api.");
      // Defensive fallback for hostnames that don't fit either
      // pattern — point at the root `api.` so the widget still has
      // somewhere to ask.
      return apiHost === hostname ? `https://api.wexio.io` : `https://${apiHost}`;
    }
  }

  return DEFAULT_API_BASE_HTTP;
}

/**
 * Backend response shape — matches the `WebConfigDto` returned by the
 * REST controller. The mapper below normalises it to the widget's
 * internal `WidgetConfig` shape, papering over any naming drift
 * between the two layers.
 */
/**
 * Raw shape of `GET /api/web/config/:pk`. Exported so a host that
 * proxies that endpoint (and wants to inject the result via the
 * `config` prop / `window.wexioSettings.config` to skip the widget's
 * own fetch) can convert it to the internal `WidgetConfig` with
 * `mapBackendConfig` rather than hand-building the internal shape.
 */
export interface BackendWebConfig {
  // Only the fields the widget actually CONSUMES are declared. The BE
  // response also carries `integrationId` / `name` / `publicKey` (and the
  // full payload always has), but the widget doesn't use them — they're
  // the integration's internal admin fields, not visitor config — so they
  // aren't declared here. (`allowedOrigins` was dropped from the visitor
  // response entirely; `WebOriginGuard` enforces it server-side.)
  status: "active" | "disabled" | "plan_blocked";
  defaultTab?: "HOME" | "MESSENGER" | "HELP" | "NEWS" | "PROFILE";
  /** UI-language strategy — `"AUTO"` / `"WEBSITE"` / `"DEFAULT"`. Absent
   *  on legacy rows → mapped to `"AUTO"`. */
  localeStrategy?: "AUTO" | "WEBSITE" | "DEFAULT";
  /** Integration's canonical / fallback language (BCP-47). Resolves
   *  `localeStrategy: "DEFAULT"`. Absent → `"en"`. */
  defaultLocale?: string;
  /** Languages the operator enabled (drives the switcher); always
   *  includes `defaultLocale`. BE-sent; not consumed by the mapper yet. */
  supportedLocales?: string[];
  /** The locale actually served for this response (echoed back). BE-sent;
   *  declared so a full payload passes through `mapBackendConfig`. */
  locale?: string;
  /** Visitor-auth config — sign-in methods (Google / passkey) + the
   *  `requireAuth` composer gate. Absent on legacy rows → all-off
   *  default. `google.clientId` is the operator's PUBLIC Google OAuth
   *  identifier (same one their main-site login uses) — the widget
   *  runs GIS directly with it. The BE verifies `id_token.aud` against
   *  the same stored value server-side, so a leaked clientId can't be
   *  abused (Google's redirect-URI allowlist + the BE audience check
   *  are the actual security boundaries). */
  security?: {
    requireAuth?: boolean;
    google?: { enabled?: boolean; clientId?: string | null };
    passkey?: { enabled?: boolean };
  } | null;
  theme?: Record<string, unknown> | null;
  features?: {
    home?: boolean;
    messenger?: boolean;
    help?: boolean;
    news?: boolean;
    profile?: boolean;
  } | null;
  prechatForm?: {
    enabled?: boolean;
    fields?: Array<{
      kind?: string;
      key?: string;
      label?: string;
      required?: boolean;
    }>;
  } | null;
  homeLayout?: unknown[] | null;
  /** Per-mode logo URLs — already flattened from Media refs by the BE. */
  logo?: { light?: string | null; dark?: string | null } | null;
  operatorAvatars?: Array<{ src?: string; alt?: string }> | null;
  greeting?: { headline?: string; subheadline?: string } | null;
  branding?: { hidden?: boolean } | null;
  /** Turnstile bot-protection surface. The BE sends it; the widget's
   *  mapper doesn't consume it yet — declared so a full BE payload can be
   *  passed through `mapBackendConfig` without an excess-property error. */
  botProtection?: {
    turnstile?: { enabled?: boolean; siteKey?: string | null };
  } | null;
  sounds?: {
    enabled?: boolean;
    inboundSoundId?: string | null;
    outboundSoundId?: string | null;
    volume?: number;
  } | null;
  messenger?: {
    title?: string | null;
    description?: string | null;
    /** BE flattens the Media `_id` → CDN URL before sending. */
    aiAssistantAvatar?: string | null;
    commands?: string[] | null;
    messages?: Array<{
      kind?: string;
      text?: string;
    }> | null;
    showRelatedNews?: boolean;
    showRelatedHelpArticles?: boolean;
    showReactionCounts?: boolean;
  } | null;
}

/**
 * In-flight + session cache for `fetchWebConfig`, keyed by
 * `publicKey|locale`. The widget reload mounts ~5 components that each
 * call `useWidgetConfig` → `fetchWebConfig` in the same tick; without
 * dedup that's 5 identical `GET /config` requests. The config is an
 * idempotent GET that only varies by `(publicKey, locale)`, so all
 * concurrent callers share ONE request, and a resolved value is reused
 * for the rest of the session (config doesn't change mid-session; a
 * locale switch is a different key → its own fetch). Failures evict the
 * entry so a later mount can retry instead of being stuck on `null`.
 */
const webConfigCache = new Map<string, Promise<WidgetConfig | null>>();

/**
 * Fetches the public widget config. Resolves to `null` on any failure
 * — caller falls back to mock data rather than surfacing the error
 * (the widget should never show a "couldn't load" screen; the
 * operator's dashboard surfaces config errors separately).
 *
 * De-duplicated per `(publicKey, locale)` — see `webConfigCache`.
 */
export function fetchWebConfig(publicKey: string, locale?: string): Promise<WidgetConfig | null> {
  if (!publicKey) return Promise.resolve(null);
  const cacheKey = `${publicKey}|${locale ?? ""}`;
  const inflight = webConfigCache.get(cacheKey);
  if (inflight) return inflight;

  const request = (async (): Promise<WidgetConfig | null> => {
    try {
      // `?locale=` lets the BE resolve the per-locale chrome overrides
      // (greeting / messenger / prechat / home layout) server-side and
      // return already-localized base fields + the served `locale`. Omit
      // it → BE serves the integration's default-locale copy.
      const url = new URL(`${apiBase()}/api/web/config/${encodeURIComponent(publicKey)}`);
      if (locale) url.searchParams.set("locale", locale);
      const res = await fetch(url.toString(), {
        method: "GET",
        headers: { "x-web-public-key": publicKey },
        credentials: "omit",
      });
      if (!res.ok) return null;
      const data = (await res.json()) as BackendWebConfig;
      return mapBackendConfig(data);
    } catch {
      return null;
    }
  })();

  // Cache the in-flight promise so concurrent callers share it. Evict on
  // a `null` result (or rejection, defensively) so a transient failure
  // doesn't poison the cache for the rest of the session.
  webConfigCache.set(
    cacheKey,
    request.then((value) => {
      if (value === null) webConfigCache.delete(cacheKey);
      return value;
    }),
  );
  return webConfigCache.get(cacheKey) ?? request;
}

const PRECHAT_KINDS: readonly PrechatFieldKind[] = ["NAME", "EMAIL", "PHONE", "CUSTOM_TEXT"];

/**
 * Defensively normalise the BE prechat shape — operators on legacy
 * rows may have partial / null fields. Unknown `kind` values are
 * dropped (rather than rendered as a broken input) so a future BE
 * enum extension doesn't crash the widget at runtime.
 */
// `TEXT` removed alongside the WEB_VISITOR_VISIT flow-trigger landing —
// proactive bot bubbles now arrive through SSE from the flow runner.
// BE filters TEXT rows out of the visitor payload defensively, but we
// keep this allow-list narrow so a legacy row sneaking through still
// drops silently rather than rendering.
const MESSENGER_MESSAGE_KINDS = ["HINT", "SYSTEM"] as const;

/**
 * Map the BE's `messenger` sub-doc to the widget's shape. Returns
 * `null` only when the BE explicitly sends `null` — operators who
 * haven't configured anything still get a defaults-bearing object
 * so the widget renders consistently. Defensive filters: unknown
 * `kind` values drop, non-string commands drop, length caps apply
 * client-side too (BE caps but we don't trust on read).
 */
function mapMessenger(raw: BackendWebConfig["messenger"]): WidgetConfig["messenger"] {
  if (raw === null) return null;
  if (!raw) {
    // BE didn't include the field at all — treat as "no operator
    // overrides", which is the same shape as `null` from the
    // widget's perspective.
    return null;
  }
  const commands = Array.isArray(raw.commands)
    ? raw.commands.filter((c): c is string => typeof c === "string" && c.length > 0).slice(0, 20)
    : [];
  const messages = Array.isArray(raw.messages)
    ? raw.messages
        .filter(
          (m): m is { kind: string; text: string } =>
            !!m &&
            typeof m.text === "string" &&
            m.text.length > 0 &&
            typeof m.kind === "string" &&
            (MESSENGER_MESSAGE_KINDS as readonly string[]).includes(m.kind),
        )
        .map((m) => ({
          kind: m.kind as "HINT" | "SYSTEM",
          text: m.text,
        }))
        .slice(0, 10)
    : [];
  return {
    title: raw.title ?? null,
    description: raw.description ?? null,
    aiAssistantAvatar: raw.aiAssistantAvatar ?? null,
    commands,
    messages,
    showRelatedNews: raw.showRelatedNews ?? true,
    showRelatedHelpArticles: raw.showRelatedHelpArticles ?? true,
    showReactionCounts: raw.showReactionCounts ?? false,
  };
}

function mapPrechatForm(raw: BackendWebConfig["prechatForm"]): WidgetPrechatForm | null {
  if (!raw) return null;
  const fields = Array.isArray(raw.fields) ? raw.fields : [];
  const mapped = fields
    .filter((f) => f && PRECHAT_KINDS.includes(f.kind as PrechatFieldKind))
    .map((f) => ({
      kind: f.kind as PrechatFieldKind,
      key: String(f.key ?? ""),
      label: String(f.label ?? ""),
      required: Boolean(f.required),
    }))
    .filter((f) => f.key.length > 0);
  return {
    enabled: Boolean(raw.enabled),
    fields: mapped,
  };
}

/**
 * Normalise the raw BE config payload (`BackendWebConfig`) to the
 * widget's internal `WidgetConfig`. Exported for hosts that already
 * hold the BE response (proxied / server-rendered) and want to inject
 * it via the `config` prop without re-fetching — `configBase` expects
 * `WidgetConfig`, not the BE shape, so run it through here first.
 */
export function mapBackendConfig(data: BackendWebConfig): WidgetConfig {
  return {
    // `integrationId` / `name` / `publicKey` are intentionally NOT mapped —
    // they're the integration's internal admin fields, not part of the
    // visitor `WidgetConfig`. The widget keys per-integration state off the
    // publicKey it already holds and shows `messenger.title`.
    status: data.status,
    defaultTab: (data.defaultTab?.toLowerCase() ?? "home") as WidgetConfig["defaultTab"],
    // UI-language strategy — pass through verbatim. Legacy rows without
    // the field default to browser-detect (`AUTO`).
    localeStrategy: data.localeStrategy ?? "AUTO",
    // Canonical language — resolves `localeStrategy: "DEFAULT"`. Legacy
    // rows / demo default to English.
    defaultLocale: data.defaultLocale ?? "en",
    // Visitor-auth config — normalised so the widget never null-checks
    // deep. Legacy rows (no `security`) default to all-off.
    security: {
      requireAuth: data.security?.requireAuth ?? false,
      google: {
        enabled: data.security?.google?.enabled ?? false,
        clientId: data.security?.google?.clientId ?? null,
      },
      passkey: {
        enabled: data.security?.passkey?.enabled ?? false,
      },
    },
    features: {
      home: data.features?.home ?? true,
      messenger: data.features?.messenger ?? true,
      help: data.features?.help ?? true,
      news: data.features?.news ?? true,
      // Profile is ON by default — the visitor profile / preferences
      // surface is part of the widget's first-class feature set. Operators
      // can still opt OUT explicitly by setting `features.profile: false`.
      profile: data.features?.profile ?? true,
    },
    theme: (data.theme as WidgetConfig["theme"]) ?? null,
    themeMode: "auto",
    prechatForm: mapPrechatForm(data.prechatForm),
    // Operator avatars — BE surfaces `{ src, alt }` (already flattened
    // from Media refs). Drop any entry missing a `src` so the header
    // never renders a broken `<img>`.
    operatorAvatars: Array.isArray(data.operatorAvatars)
      ? data.operatorAvatars
          .filter((a): a is { src: string; alt?: string } => !!a?.src)
          .map((a) => ({ src: a.src, alt: a.alt ?? "" }))
      : [],
    // Per-mode logo. BE sends `{ light, dark }` (or null). Normalise
    // missing fields to `null` so the shell's resolve-by-mode logic
    // has a stable shape.
    organizationLogo: data.logo
      ? {
          light: data.logo.light ?? null,
          dark: data.logo.dark ?? null,
        }
      : null,
    // Greeting — empty strings (or a null BE greeting) → HomeTab
    // falls back to i18n defaults (`messages/<locale>.json#home.*`).
    // Operator-set strings override the default in any locale.
    greeting: {
      headline: data.greeting?.headline ?? "",
      subheadline: data.greeting?.subheadline ?? "",
    },
    // `homeLayout` is operator JSON — pass it through verbatim; the
    // Home renderer validates per-block and falls back to
    // `DEFAULT_HOME_LAYOUT` when this is `null`.
    homeLayout: (data.homeLayout as WidgetConfig["homeLayout"]) ?? null,
    branding: data.branding?.hidden ? { hidden: true } : null,
    // Prechat form already set above.
    sounds: data.sounds
      ? {
          enabled: data.sounds.enabled ?? true,
          inboundSoundId: data.sounds.inboundSoundId ?? null,
          outboundSoundId: data.sounds.outboundSoundId ?? null,
          volume:
            typeof data.sounds.volume === "number"
              ? Math.max(0, Math.min(1, data.sounds.volume))
              : 0.5,
        }
      : null,
    messenger: mapMessenger(data.messenger),
  };
}

/**
 * Convert a raw BE config payload into the shape a host may INJECT
 * (`config` prop / `window.wexioSettings.config`) — i.e. the full
 * `WidgetConfig` MINUS the BE-owned fields a host must never supply
 * (`branding`, `status`, `integrationId`, `name`). Use this (not
 * `mapBackendConfig`) when a host proxies `GET /api/web/config` and wants
 * to inject it: the result is type-narrowed to `InjectableWidgetConfig`,
 * so the protected fields are dropped at the type level. They're re-fetched
 * authoritatively from the BE by publicKey (the lite `?view=gate` config,
 * see `fetchWebGate`) regardless of injection, so nothing is lost.
 */
export function toInjectableConfig(data: BackendWebConfig): InjectableWidgetConfig {
  const { branding: _branding, status: _status, ...injectable } = mapBackendConfig(data);
  return injectable;
}

/**
 * The plan / restriction gate the widget needs BEFORE auth and must NOT
 * trust from host-injected config. Always fetched from the BE by publicKey
 * (the lite `?view=gate` config), even when presentation is injected — so
 * a host can't fake white-label removal or the plan gate. Matches the BE's
 * gate payload exactly: `{ status, branding: { hidden } }`.
 */
export interface WebGate {
  status: WidgetConfig["status"];
  /** Plan-coerced server-side; `{ hidden: true }` only when the plan
   *  allows white-label AND the operator turned it on. `null` = shown. */
  branding: WidgetConfig["branding"];
  /** Visitor-auth config — surfaced here too so a host that injects
   *  presentation config CAN'T forge `security.google.clientId` (the
   *  BE-stored Google OAuth client id paired with the BE-side
   *  audience check). Hosts may still influence `enabled` flags via
   *  the injectable config; `clientId` is always the BE's value. */
  security: WidgetConfig["security"];
}

const webGateCache = new Map<string, Promise<WebGate | null>>();

/**
 * Fetch ONLY the plan/restriction gate for a publicKey — the lite
 * `?view=gate` view of the config endpoint (`{ status, branding }`). Used
 * when a host injects presentation config: the widget skips the heavy
 * config but STILL fetches this small authoritative gate so branding +
 * status stay server-owned. De-duplicated per publicKey like
 * `fetchWebConfig`. (A full payload also carries these two fields, so this
 * works even if `?view=gate` isn't honored.)
 */
export function fetchWebGate(publicKey: string): Promise<WebGate | null> {
  if (!publicKey) return Promise.resolve(null);
  const cached = webGateCache.get(publicKey);
  if (cached) return cached;

  const request = (async (): Promise<WebGate | null> => {
    try {
      const url = new URL(`${apiBase()}/api/web/config/${encodeURIComponent(publicKey)}`);
      url.searchParams.set("view", "gate");
      const res = await fetch(url.toString(), {
        method: "GET",
        headers: { "x-web-public-key": publicKey },
        credentials: "omit",
      });
      if (!res.ok) return null;
      const data = (await res.json()) as Partial<BackendWebConfig>;
      // Surface the BE-owned security block alongside the gate so a
      // host that injects presentation config still picks up the BE's
      // `clientId` + `enabled` defaults when it omits them. `clientId`
      // is a PUBLIC Google OAuth identifier — same one the operator
      // embeds on their main-site login; safe to ship to the visitor.
      // The actual trust boundary is the BE's audience check (it
      // verifies `id_token.aud` against the same stored clientId
      // server-side). Defaults all-off so a sparse BE response
      // degrades safely.
      return {
        status: (data.status as WidgetConfig["status"]) ?? "active",
        branding: data.branding?.hidden ? { hidden: true } : null,
        security: {
          requireAuth: data.security?.requireAuth ?? false,
          google: {
            enabled: data.security?.google?.enabled ?? false,
            clientId: data.security?.google?.clientId ?? null,
          },
          passkey: {
            enabled: data.security?.passkey?.enabled ?? false,
          },
        },
      };
    } catch {
      return null;
    }
  })();

  webGateCache.set(
    publicKey,
    request.then((value) => {
      if (value === null) webGateCache.delete(publicKey);
      return value;
    }),
  );
  return webGateCache.get(publicKey) ?? request;
}
