"use client";

import { useLocale } from "next-intl";
import { useEffect, useMemo, useState } from "react";
import { fetchWebConfig, fetchWebGate } from "./api";
import { ensureThemeFont } from "./theme-font";
import { useWidgetEnv } from "./use-widget-env";
import {
  DEMO_CONFIG,
  type WidgetConfig,
  type WidgetMode,
  type WidgetTheme,
  type WidgetThemePalette,
  type WidgetThemeRadii,
} from "./widget-config";

/**
 * Resolves the widget's runtime mode + active `WidgetConfig`.
 *
 * **Mode** is the ambient UX (close button visibility, postMessage
 * subscription, dashboard-specific affordances):
 *
 *   - `?pk=<publicKey>`        → production
 *   - `?mode=preview`          → preview (dashboard live edit)
 *   - default                  → demo (marketing / first-load)
 *
 * **Data source** is orthogonal to mode — every mode tries the real
 * REST config endpoint first and only falls back to `DEMO_CONFIG`
 * when no `publicKey` is available or the fetch fails. `isDummy`
 * surfaces the fallback state so non-production surfaces can paint a
 * subtle "demo data" badge.
 *
 * Resolution order for the `publicKey`:
 *   1. `?pk=` URL param (production / dashboard preview pointing at an integration)
 *   2. `NEXT_PUBLIC_WEXIO_DEMO_PK` env var (marketing-site demo integration)
 *   3. None → fall back to bundled `DEMO_CONFIG`
 *
 * **Three layers compose into the effective config:**
 *   1. **base** — resolved from the BE (`fetchWebConfig`) or `DEMO_CONFIG`.
 *   2. **postMessage patch** — accumulated `wexio:preview-config:v1`
 *      events (iframe preview path; dashboard posts to the iframe).
 *   3. **`env.configOverride`** — a live `Partial<WidgetConfig>` prop
 *      threaded by the `<WexioWidget>` React embed (dashboard theme
 *      editor's in-progress draft; no serialization round-trip).
 *
 * Higher layers win. The effective config is `useMemo`'d so a draft
 * edit re-renders the tree without a fetch, and a single effect
 * re-applies the theme CSS vars whenever the effective `theme`
 * reference changes.
 */
export function useWidgetConfig(): {
  mode: WidgetMode;
  config: WidgetConfig;
  isDummy: boolean;
  isLoading: boolean;
} {
  // Web-component mode supplies its own pk / mode via the env context
  // (the embed's `<wexio-widget>` attributes). Iframe mode leaves both
  // undefined and we fall through to the URL/env resolution below —
  // preserves the loader.js flow exactly.
  const env = useWidgetEnv();
  // Visitor's resolved UI locale (see `locale-detect` → NextIntlClient
  // Provider). Threaded into the config fetch so the BE serves the
  // operator's localized chrome for THIS language; re-fetches on change
  // (e.g. a language switcher) since it's an effect dependency below.
  const locale = useLocale();
  // BASE layer — resolved from BE or DEMO. Never carries preview
  // patches; those live in their own layers so a late BE response
  // can't clobber an in-flight edit.
  const [base, setBase] = useState<{
    mode: WidgetMode;
    config: WidgetConfig;
    isDummy: boolean;
    isLoading: boolean;
  }>({
    mode: "demo",
    config: DEMO_CONFIG,
    isDummy: true,
    isLoading: true,
  });
  // POSTMESSAGE layer — accumulated `wexio:preview-config:v1` patches
  // (iframe preview path). `null` until the first event arrives.
  const [postMessagePatch, setPostMessagePatch] = useState<Partial<WidgetConfig> | null>(null);

  useEffect(() => {
    const url = new URL(window.location.href);
    const pkFromUrl = url.searchParams.get("pk") ?? undefined;
    const pkFromEnv = process.env.NEXT_PUBLIC_WEXIO_DEMO_PK || undefined;
    const explicitMode = url.searchParams.get("mode");

    const publicKey = env.publicKeyOverride ?? pkFromUrl ?? pkFromEnv;

    const mode: WidgetMode =
      env.modeOverride ??
      (publicKey ? "production" : explicitMode === "preview" ? "preview" : "demo");

    let cancelled = false;

    const resolve = async () => {
      // Host-injected PRESENTATION config → skip the HEAVY config fetch
      // (theme / messenger / homeLayout / …) and render those from props.
      // But the plan / restriction / identity gate (`branding`, `status`,
      // `integrationId`, `name`) is ALWAYS fetched authoritatively from the
      // BE by publicKey — a host must never be able to fake white-label
      // removal or the plan gate from props. So we do a small `?view=gate`
      // fetch and merge it OVER the injected presentation. `configOverride`
      // still merges on top (below).
      if (env.configBase) {
        const gate = publicKey ? await fetchWebGate(publicKey) : null;
        if (cancelled) return;
        // Resolve `security` with the BE as the source of truth for
        // sensitive fields, allowing the host to influence ONLY the
        // method-enabled flags:
        //   - `clientId`   → ALWAYS from BE (paired with BE's Google
        //     audience check; a host-supplied value would let them
        //     direct visitors to their own OAuth client).
        //   - `requireAuth` → ALWAYS from BE (server-side enforcement
        //     anyway; letting the host override only desyncs UI).
        //   - `google.enabled` / `passkey.enabled` → host's value wins
        //     when explicitly set; otherwise the BE default is used.
        const hostSec = env.configBase.security;
        const beSec = gate?.security;
        const resolvedSecurity: WidgetConfig["security"] = {
          // `requireAuth` is BE-enforced server-side (the visitor JWT
          // guard rejects unverified writes when the integration
          // requires auth), so the host's UI hint is safe to honour
          // when the BE gate is unavailable — without it the inject
          // test harness can't render the sign-in gate at all.
          requireAuth: hostSec?.requireAuth ?? beSec?.requireAuth ?? false,
          google: {
            enabled: hostSec?.google?.enabled ?? beSec?.google?.enabled ?? false,
            // `clientId` is BE-ONLY. Hosts can't inject it via props
            // (the type strips it from `InjectableWidgetSecurity`),
            // and the widget always reads the live value from the BE
            // gate fetch — keeps it in lockstep with the BE's
            // audience check on `startIdentifiedVisitor`. `null` when
            // the BE gate fetch failed / there's no publicKey, which
            // hides the button (see `MessagesTab`).
            clientId: beSec?.google?.clientId ?? null,
          },
          passkey: {
            enabled: hostSec?.passkey?.enabled ?? beSec?.passkey?.enabled ?? false,
          },
        };
        // Spread the host config (less `security`, which we rebuild
        // above), then stamp the resolved security + the BE gate. The
        // type-level `InjectableWidgetConfig` already strips `clientId`
        // / `requireAuth` from the host-supplied shape; this is the
        // runtime defence in depth.
        const { security: _ignoredHostSecurity, ...presentation } = env.configBase;
        setBase({
          mode,
          config: {
            ...presentation,
            security: resolvedSecurity,
            // Plan/restriction gate — BE-owned, never from props. Safe
            // defaults if the gate fetch failed / there's no publicKey.
            branding: gate?.branding ?? null,
            status: gate?.status ?? "active",
          },
          isDummy: env.forceDummyData === true,
          isLoading: false,
        });
        return;
      }

      // The operator dashboard's preview pane embeds the widget with a
      // `useDummyData` prop (host knows whether it wants the mock data
      // layer or the real one) AND threads the operator's full config
      // through `configOverride`. The REST bootstrap fetch would 403
      // anyway — the dashboard's origin isn't on the operator's
      // `allowedOrigins`, that allow-list is for the visitor's host
      // page — so skip it entirely and trust the host. `isDummy` then
      // reflects the toggle directly.
      if (env.forceDummyData !== undefined) {
        setBase({
          mode,
          config: DEMO_CONFIG,
          isDummy: env.forceDummyData,
          isLoading: false,
        });
        return;
      }

      if (publicKey) {
        const real = await fetchWebConfig(publicKey, locale);
        if (cancelled) return;
        if (real) {
          setBase({ mode, config: real, isDummy: false, isLoading: false });
          return;
        }
      }
      // No publicKey OR the fetch failed → fall back to bundled mock.
      // Demo + preview surfaces can still operate; production sees an
      // empty-state header.
      setBase({ mode, config: DEMO_CONFIG, isDummy: true, isLoading: false });
    };

    resolve();

    if (mode !== "preview")
      return () => {
        cancelled = true;
      };

    const onMessage = (event: MessageEvent) => {
      if (!event.data || typeof event.data !== "object") return;
      if (event.data.type !== "wexio:preview-config:v1") return;
      const patch = event.data.config as Partial<WidgetConfig> | undefined;
      if (!patch) return;
      // Accumulate onto the existing patch layer — a dashboard that
      // posts `{ theme }` then `{ features }` should end up with both.
      setPostMessagePatch((prev) => mergeConfigPatch(prev ?? {}, patch));
    };

    window.addEventListener("message", onMessage);
    return () => {
      cancelled = true;
      window.removeEventListener("message", onMessage);
    };
    // Re-resolve when the embed surface swaps its overrides — happens
    // in web-component mode when the host page mutates the
    // `public-key` attribute on `<wexio-widget>`. Iframe mode keeps
    // both overrides `undefined` so the effect runs exactly once.
    // Dashboard preview path: `forceDummyData` flip needs to re-resolve
    // so the new `isDummy` lands on `base` (visitor flow re-derives).
    // `locale` re-fetches the BE config in the new language.
  }, [env.publicKeyOverride, env.modeOverride, env.forceDummyData, env.configBase, locale]);

  // `forceDummyData` lets the operator dashboard's preview pane show the
  // bundled mock content layer (messages / articles / news / FAQs /
  // launcher unread) on top of an otherwise-real config — useful for a
  // brand-new integration with empty BE content. It only toggles the data
  // layer; operator config (theme, logo, greeting, etc.) flows through
  // either way via the `configOverride` merge below.
  const effectiveIsDummy = base.isDummy || env.forceDummyData === true;

  // Effective config = base ← postMessage patch ← configOverride prop.
  //
  // When the effective config is in dummy mode AND the operator hasn't
  // uploaded any avatars, fall back to the bundled DEMO_CONFIG avatars so
  // the dashboard preview shows a populated header. The logo / greeting
  // stay live — they're operator-config, not content.
  const config = useMemo(() => {
    let c = base.config;
    if (postMessagePatch) c = mergeConfigPatch(c, postMessagePatch);
    if (env.configOverride) c = mergeConfigPatch(c, env.configOverride);
    if (effectiveIsDummy && c.operatorAvatars.length === 0) {
      c = { ...c, operatorAvatars: DEMO_CONFIG.operatorAvatars };
    }
    return c;
  }, [base.config, postMessagePatch, env.configOverride, effectiveIsDummy]);

  // Re-apply the theme CSS-variable block whenever the effective
  // theme changes reference — covers BE arrival, postMessage patches,
  // AND the configOverride prop in one place. `config.theme` is a
  // stable reference when no layer touched it (see `mergeConfigPatch`),
  // so this only fires on a real theme change.
  //
  // `env.styleRoot` decides WHERE the token `<style>` lands: the
  // React-component embed points it at its Shadow DOM so theming is
  // self-contained; iframe / web-component builds leave it undefined
  // and fall back to `document` (→ `<head>`).
  const styleRoot = env.styleRoot;
  useEffect(() => {
    if (config.theme) {
      applyThemeOverrides(config.theme, styleRoot ?? document);
      // The operator can pick a Google Font the bundle doesn't ship —
      // fetch it so `--wx-font` resolves to the real face instead of
      // silently falling back to `system-ui`.
      ensureThemeFont(config.theme.fontFamily);
    }
  }, [config.theme, styleRoot]);

  // Phase 2 of locale resolution (embeds only): now that the config has
  // resolved we know the operator's `localeStrategy`. Hand it back to the
  // embed wrapper so it can re-resolve the visitor's UI language —
  // switching to the host page's `<html lang>` for `WEBSITE`, or to a
  // pinned code. The wrapper updates the provider locale, which flips
  // `useLocale()` and re-runs the fetch effect above in the new language.
  //
  // Safe to fire on every strategy change: `detectClientLocale(strategy)`
  // is deterministic, so a wrapper that re-resolves to the same locale
  // does a no-op `setState`. The iframe leaves `onLocaleStrategy`
  // undefined — its loader already resolved the strategy via `?lang=`.
  const onLocaleStrategy = env.onLocaleStrategy;
  useEffect(() => {
    // Translate the `DEFAULT` strategy to the integration's canonical
    // locale code before handing it down — `detectClientLocale` then
    // pins to that code. `AUTO` / `WEBSITE` pass through as-is.
    const resolved =
      config.localeStrategy === "DEFAULT" ? config.defaultLocale : config.localeStrategy;
    onLocaleStrategy?.(resolved);
  }, [onLocaleStrategy, config.localeStrategy, config.defaultLocale]);

  return {
    mode: base.mode,
    config,
    isDummy: effectiveIsDummy,
    isLoading: base.isLoading,
  };
}

/**
 * Merge a `Partial<WidgetConfig>` patch onto a base. Used both to
 * accumulate postMessage patches (base is itself a partial) and to
 * apply a patch layer onto the full resolved config.
 *
 * `features` + `greeting` deep-merge so a patch touching one key
 * doesn't wipe the siblings. `theme` is replaced wholesale — the
 * dashboard editor holds the complete theme object in state, so a
 * partial-theme patch would be the editor's bug, not ours; replacing
 * also keeps `config.theme` referentially stable when no patch
 * touches it (the theme-apply effect depends on that). Everything
 * else is a shallow replace.
 */
function mergeConfigPatch<T extends Partial<WidgetConfig>>(
  base: T,
  patch: Partial<WidgetConfig>,
): T {
  return {
    ...base,
    ...patch,
    features: { ...(base.features ?? {}), ...(patch.features ?? {}) },
    greeting: { ...(base.greeting ?? {}), ...(patch.greeting ?? {}) },
    theme: patch.theme === undefined ? base.theme : patch.theme,
  } as T;
}

/**
 * Designer-friendly palette name → CSS custom property. Mirrors the
 * `WidgetThemePalette` shape; the values are the variables defined
 * in `app/globals.css` for both `:root` (light) and
 * `[data-theme="dark"]` (dark).
 *
 * Lookup table only — `applyThemeOverrides` iterates the palette
 * the operator sent and writes one declaration per matched key.
 * Unmatched keys are silently ignored so future schema additions
 * (BE ships a new token before the widget knows about it) don't
 * crash the apply step.
 */
const PALETTE_CSS_VARS: Record<keyof WidgetThemePalette, string> = {
  background: "--wx-bg",
  surface: "--wx-bg-elevated",
  surfaceElevated: "--wx-bg-elevated-2",
  text: "--wx-fg",
  textMuted: "--wx-fg-muted",
  textSubtle: "--wx-fg-subtle",
  border: "--wx-border",
  borderStrong: "--wx-border-strong",
  primary: "--wx-primary",
  primaryHover: "--wx-primary-hover",
  primaryForeground: "--wx-primary-fg",
  launcherBackground: "--wx-launcher-bg",
  launcherForeground: "--wx-launcher-fg",
  success: "--wx-success",
  danger: "--wx-danger",
};

const RADII_CSS_VARS: Record<keyof WidgetThemeRadii, string> = {
  sm: "--wx-radius-sm",
  md: "--wx-radius",
  lg: "--wx-radius-lg",
  xl: "--wx-radius-xl",
};

/**
 * Build the `prop: value;` declaration list for one palette. Skips
 * empty / non-string values so a partial palette doesn't emit
 * `--wx-bg: undefined`.
 */
function paletteDeclarations(palette: WidgetThemePalette | undefined): string {
  if (!palette) return "";
  return (Object.entries(palette) as [keyof WidgetThemePalette, unknown][])
    .filter(([, v]) => typeof v === "string" && (v as string).length > 0)
    .map(([key, v]) => `${PALETTE_CSS_VARS[key]}: ${v as string};`)
    .join(" ");
}

function radiiDeclarations(radii: WidgetThemeRadii | undefined): string {
  if (!radii) return "";
  return (Object.entries(radii) as [keyof WidgetThemeRadii, unknown][])
    .filter(([, v]) => typeof v === "number" && Number.isFinite(v))
    .map(([key, v]) => `${RADII_CSS_VARS[key]}: ${v as number}px;`)
    .join(" ");
}

/**
 * Per-shadow-root operator-theme `CSSStyleSheet`. Keyed by shadow root
 * so multiple `<WexioWidget>` instances on one page (e.g. the
 * dashboard's desktop + mobile preview panes) each get their own.
 */
const themeSheets = new WeakMap<ShadowRoot, CSSStyleSheet>();

/** Build the operator-theme CSS text — two selector blocks:
 *
 *   :root, :host              { ...light + radii + font }
 *   [data-theme="dark"]       { ...dark + radii + font }
 *
 * `:root` matches `<html>` in the iframe / web-component builds; `:host`
 * matches the shadow host in the React-component embed — so the
 * light/default tokens land regardless of which tree the widget lives
 * in. `[data-theme="dark"]` matches whatever `useThemeMode` stamped the
 * attribute on (`<html>` or the shadow portal target). Radii + font live
 * on both blocks because the dark block overrides the light one. */
function buildThemeCss(theme: WidgetTheme): string {
  const radiiDecls = radiiDeclarations(theme.radii);
  const fontDecl =
    typeof theme.fontFamily === "string" && theme.fontFamily.trim().length > 0
      ? `--wx-font: ${theme.fontFamily};`
      : "";
  const invariantDecls = [radiiDecls, fontDecl].filter(Boolean).join(" ");
  const lightDecls = [paletteDeclarations(theme.light), invariantDecls].filter(Boolean).join(" ");
  const darkDecls = [paletteDeclarations(theme.dark), invariantDecls].filter(Boolean).join(" ");

  const blocks: string[] = [];
  if (lightDecls) blocks.push(`:root, :host { ${lightDecls} }`);
  if (darkDecls) blocks.push(`[data-theme="dark"] { ${darkDecls} }`);
  return blocks.join(" ");
}

/**
 * Apply operator theme overrides into `styleRoot`.
 *
 *   - `ShadowRoot` (React-component embed) → a constructable
 *     `CSSStyleSheet` appended LAST to `shadowRoot.adoptedStyleSheets`.
 *     This is the critical bit: `adoptedStyleSheets` are ordered AFTER
 *     a shadow tree's `<style>` children in the cascade, and the
 *     bundled `globals.css` is itself an adopted sheet — so a plain
 *     `<style>` child would LOSE to `globals.css`'s built-in token
 *     defaults and the operator's colours would never show. The
 *     override must be an adopted sheet appended after `globals.css`.
 *     (Old browsers with no constructable-stylesheet support fall back
 *     to a `<style>` child — there `globals.css` is also a `<style>`
 *     child, so source order still lets the override win.)
 *   - `Document` (iframe / web-component) → a `<style>` in `<head>`,
 *     appended after `globals.css` so it wins by source order.
 *
 * The sheet / element is reused across renders so toggling theme mode
 * never duplicates it.
 */
function applyThemeOverrides(theme: WidgetTheme, styleRoot: ShadowRoot | Document) {
  const css = buildThemeCss(theme);

  if (!(styleRoot instanceof Document)) {
    const shadow = styleRoot;
    const supportsConstructable =
      typeof CSSStyleSheet !== "undefined" && "replaceSync" in CSSStyleSheet.prototype;

    if (supportsConstructable) {
      let sheet = themeSheets.get(shadow);
      if (!sheet) {
        sheet = new CSSStyleSheet();
        themeSheets.set(shadow, sheet);
        // Append LAST — must sit after the adopted `globals.css`.
        shadow.adoptedStyleSheets = [...shadow.adoptedStyleSheets, sheet];
      }
      sheet.replaceSync(css);
      return;
    }

    // Fallback: no constructable stylesheets — `globals.css` is a
    // `<style data-wexio-style>` child here too, so a later `<style>`
    // child wins by source order.
    let styleEl = shadow.querySelector<HTMLStyleElement>("#wexio-theme-vars");
    if (!styleEl) {
      styleEl = document.createElement("style");
      styleEl.id = "wexio-theme-vars";
      shadow.appendChild(styleEl);
    }
    styleEl.textContent = css;
    return;
  }

  // `Document` — inject a `<style>` into `<head>`.
  let style = styleRoot.getElementById("wexio-theme-vars") as HTMLStyleElement | null;
  if (!style) {
    style = document.createElement("style");
    style.id = "wexio-theme-vars";
    styleRoot.head.appendChild(style);
  }
  style.textContent = css;
}
