/**
 * Web-font loading for the operator's chosen `theme.fontFamily`.
 *
 * The dashboard's font picker offers a handful of Google Fonts that the
 * widget bundle does NOT ship — selecting one would silently fall back
 * to `system-ui` unless the font file is actually fetched. This module
 * injects the matching Google Fonts `<link>` on demand.
 *
 * The `<link>` goes into the HOST document's `<head>`, never the Shadow
 * DOM: `@font-face` rules loaded in the top-level document ARE visible
 * to shadow trees, but a `<link>` placed inside a shadow root is not a
 * reliable way to load fonts. System stacks (Geist, `system-ui`, an
 * operator's own self-hosted family) match nothing here and are no-ops.
 */

/**
 * Operator-selectable Google Fonts → their `family=` query value.
 * Mirrors the dashboard's `FontFamilySelect` list. Lowercase keys so
 * the lookup is case-insensitive.
 */
const GOOGLE_FONTS: Record<string, string> = {
  inter: "Inter:wght@400;500;600;700",
  poppins: "Poppins:wght@400;500;600;700",
  "dm sans": "DM+Sans:wght@400;500;600;700",
  roboto: "Roboto:wght@400;500;700",
  "ibm plex sans": "IBM+Plex+Sans:wght@400;500;600;700",
  lato: "Lato:wght@400;700",
  montserrat: "Montserrat:wght@400;500;600;700",
  nunito: "Nunito:wght@400;500;600;700",
  raleway: "Raleway:wght@400;500;600;700",
  "work sans": "Work+Sans:wght@400;500;600;700",
};

/**
 * Make sure the web font referenced by a `font-family` stack is loaded.
 * Extracts the first family name, and if it's a known Google Font that
 * isn't already loaded, appends a `<link>` to `document.head`. Deduped
 * by font id; safe to call on every theme change.
 */
export function ensureThemeFont(fontFamily: string | undefined): void {
  if (!fontFamily || typeof document === "undefined") return;

  const first = fontFamily
    .split(",")[0]
    ?.trim()
    .replace(/^['"]|['"]$/g, "");
  if (!first) return;

  const family = GOOGLE_FONTS[first.toLowerCase()];
  if (!family) return; // System / Geist / operator-hosted — nothing to fetch.

  const id = `wexio-font-${first.toLowerCase().replace(/\s+/g, "-")}`;
  if (document.getElementById(id)) return; // Already loaded.

  const link = document.createElement("link");
  link.id = id;
  link.rel = "stylesheet";
  link.href = `https://fonts.googleapis.com/css2?family=${family}&display=swap`;
  document.head.appendChild(link);
}
