/**
 * Resolve a widget static asset (notification sounds, brand logo, …)
 * to a fetchable URL.
 *
 * The widget's static assets live in `public/` and are served from the
 * widget's OWN origin in iframe / web-component mode — there `/sounds/
 * wx-nt_3.wav` resolves correctly. The React-component embed, though,
 * runs on the HOST page's origin (e.g. `frontend-app`), where that path
 * 404s. `__WEXIO_ASSET_BASE__` is baked in at build time (see
 * `vite.react-component.config.ts` / `vite.web-component.config.ts`):
 * the widget's CDN origin for the cross-origin embeds, and left
 * undefined for the same-origin Next iframe build (→ empty base).
 */
declare const __WEXIO_ASSET_BASE__: string | undefined;

const ASSET_BASE = typeof __WEXIO_ASSET_BASE__ === "string" ? __WEXIO_ASSET_BASE__ : "";

/**
 * Prefix a `public/`-relative asset path with the build-time asset
 * base. Already-absolute URLs (operator-uploaded customs) pass through
 * untouched.
 */
export function assetUrl(path: string): string {
  if (/^https?:\/\//.test(path)) return path;
  return ASSET_BASE + (path.startsWith("/") ? path : `/${path}`);
}
