"use client";

import { createContext, type ReactNode, useContext } from "react";
import type { InjectableWidgetConfig, WidgetConfig } from "./widget-config";

/**
 * Visitor identity the host passes in to log a known user into the
 * widget (the embed equivalent of Intercom's `boot({ user_id, ... })`).
 *
 * `userId` + `userHash` are the IDENTITY — `userHash` is an
 * HMAC-SHA256(integration secret, userId) the host computes server-side,
 * which the BE re-derives and constant-time compares so a visitor can't
 * be impersonated. The rest is profile data, NOT used for auth:
 * `name` / `email` / `phone` are written to the People row, and
 * `attributes` is an open bag of extra fields forwarded as the session
 * `contextSnapshot`.
 *
 * Threaded to `useVisitorAuth`, which routes to `startIdentifiedVisitor`
 * (vs `startAnonymousVisitor`) when present.
 */
export interface VisitorIdentity {
  /** Verified user id. Required on the HMAC path (it's what `userHash`
   *  signs); optional on the `jwt` path (the BE takes it from the token's
   *  `sub`). */
  userId?: string;
  /** Legacy HMAC proof — `HMAC-SHA256(secret, userId)`. Supply with
   *  `userId`. Mutually exclusive with `jwt`. */
  userHash?: string;
  /** RECOMMENDED: a short-lived host-signed JWT (HS256). Carries
   *  `{ sub, email?, name?, phone?, exp }`; the BE verifies signature +
   *  expiry. Mutually exclusive with `userHash`. */
  jwt?: string;
  /** Google "Sign in with Google" / One-Tap `id_token` (FedCM). The BE
   *  verifies it against Google's keys with the integration's
   *  `googleClientId`. Mutually exclusive with the other proofs. */
  googleIdToken?: string;
  name?: string;
  email?: string;
  phone?: string;
  attributes?: Record<string, unknown>;
}

/**
 * Default profile values the host passes to PRE-FILL the prechat form
 * (e.g. via `?wx_email=…` URL params, a `prefill` prop, or
 * `window.wexioSettings.prefill`). Unlike `VisitorIdentity` there's no
 * `userHash` — these are UNVERIFIED, so they don't authenticate anyone;
 * they just save the visitor typing. When they cover every required
 * prechat field the widget attaches them (via the prechat write) and
 * skips the form; otherwise it pre-fills what it can and shows the rest.
 */
export interface VisitorPrefill {
  name?: string;
  email?: string;
  phone?: string;
}

/**
 * Two delivery modes:
 *
 *   - **iframe**         — host page injects `loader.js`, which renders
 *                          the widget inside an iframe. Resize / close
 *                          signals fire as `postMessage` to `window.parent`,
 *                          and the public-key comes from the iframe URL
 *                          (`?pk=...`).
 *
 *   - **web-component**  — host page mounts `<wexio-widget>` directly.
 *                          The widget runs in the host's JS context inside
 *                          a Shadow DOM. There is no parent frame to
 *                          postMessage to and no iframe URL to read; the
 *                          web-component bridge supplies the public-key
 *                          via an attribute and listens for resize / close
 *                          via `CustomEvent`s instead.
 *
 * The `WidgetShell` stays env-agnostic — it asks `useWidgetEnv()` for the
 * outbound signal handlers and trusts the host adapter to do the right
 * thing. Default values keep the iframe path working without any provider
 * (so `next dev` + Storybook continue to behave identically).
 */
export interface WidgetEnv {
  /** Which embed surface the widget is mounted into. */
  kind: "iframe" | "web-component";
  /**
   * Public-key override. Web-component mode passes the value from the
   * `<wexio-widget public-key="...">` attribute; iframe mode leaves
   * this undefined and `useWidgetConfig` reads `?pk=` from the URL.
   */
  publicKeyOverride?: string;
  /**
   * Explicit mode override (defaults to URL-driven). Web-component
   * mode pins this to `production` because the embed is for real
   * deployments — there is no demo/preview attribute path.
   */
  modeOverride?: "production" | "preview" | "demo";
  /**
   * Live config patch from a React host — the operator dashboard's
   * theme/branding editor threads its in-progress draft here via the
   * `<WexioWidget configOverride={...} />` prop. `useWidgetConfig`
   * merges it on top of the resolved config (BE / demo) AND any
   * iframe `postMessage` patches, so the preview pane reflects
   * unsaved edits instantly with no serialization round-trip.
   *
   * Iframe + web-component embeds leave this undefined — the iframe
   * uses the `wexio:preview-config:v1` postMessage channel instead.
   */
  configOverride?: Partial<WidgetConfig>;
  /**
   * Full, host-supplied widget config. When set, `useWidgetConfig` uses
   * it VERBATIM as the base and SKIPS the `GET /api/web/config/:pk`
   * bootstrap round-trip — for a host (SSR, an app shell, the dashboard)
   * that already holds the integration's config and wants the widget to
   * boot with one fewer request. `configOverride` still layers on top.
   *
   * Distinct from its two neighbours:
   *   - `configOverride` is a PARTIAL patch merged onto a FETCHED base.
   *   - `forceDummyData` swaps in `DEMO_CONFIG` + the MOCK data layer.
   *   - `configBase` is the REAL, complete config and keeps the LIVE data
   *     layer (real conversations / help / news). Combine with
   *     `forceDummyData` only if you also want mock content.
   *
   * The host owns locale-correctness: the config's localized chrome
   * (greeting / messenger / prechat) is whatever was passed, so re-inject
   * it when the visitor switches language (there's no fetch to re-run).
   *
   * The `publicKey` is still required (GraphQL header + visitor
   * handshake) — only the CONFIG fetch is skipped.
   *
   * Typed `InjectableWidgetConfig` (NOT the full `WidgetConfig`): the
   * server-/plan-owned fields (`branding`, `status`) and the integration
   * identity (`integrationId`, `name`) are excluded so a host can't
   * override them from props — `useWidgetConfig` fills those itself.
   */
  configBase?: InjectableWidgetConfig;
  /**
   * Force the widget into demo-data mode regardless of whether a real
   * `publicKey` was supplied. The operator dashboard's preview pane
   * uses this to render the bundled mock content layer (messages,
   * help articles + categories + FAQs, news items, launcher unread
   * count, …) on top of the operator's real config — so a brand-new
   * integration with empty BE-side content still shows a populated
   * widget to design against. Set `false` (or omit) and the widget
   * uses live data: real conversations, real articles, real news.
   *
   * Only affects the data layer — operator config (theme, branding,
   * logo, greeting, prechat, sounds, blocks, …) always flows through
   * untouched, in either mode.
   */
  forceDummyData?: boolean;
  /**
   * Dashboard-prefetched data for the preview pane. When set, the
   * widget reads news content from this object instead of round-
   * tripping to the BE — lets the preview render real operator data
   * without the widget's visitor-side queries hitting the
   * `WebOriginGuard` from a dashboard origin.
   *
   * Shape mirrors the visitor JSON the BE returns (id, title, excerpt,
   * coverImageUrl, externalCoverImageUrl, publishedAt, …). Components
   * that consume it use the same extractors as the live query path.
   *
   * `null` / undefined → fall through to the live query (production
   * embeds, real customer pages). Only meaningful when the dashboard
   * preview pane mounts the widget.
   */
  previewData?: {
    newsPosts?: unknown[];
    newsPostsById?: Record<string, unknown>;
    helpArticles?: unknown[];
    helpArticlesById?: Record<string, unknown>;
  };
  /**
   * Anchor the launcher + panel to the embed's host `<div>` instead of
   * the viewport. The React-component embed sets this `true` — the host
   * sizes + positions the outer `<div>` with normal layout CSS and the
   * widget fills that box (`position: absolute`), so the launcher/panel
   * never escape into a `position: fixed` viewport corner. Iframe +
   * web-component embeds leave it undefined: they own the whole viewport
   * (or their own iframe) and keep the `fixed` corner anchoring.
   */
  embedded?: boolean;
  /**
   * Render the media lightbox as a viewport-`fixed` overlay rather than
   * one `absolute`-contained to the widget's host box.
   *
   * Only meaningful when `embedded` is `true`. The dashboard's *desktop*
   * preview pane wants the lightbox contained (it's a small framed
   * mock inside a larger editor) — leave this unset. The dashboard's
   * *mobile* floating-widget preview is itself tiny, so a contained
   * lightbox would be unusable; it sets this `true` so the gallery
   * breaks out to the full viewport. The overlay still renders inside
   * the Shadow DOM either way (it keeps the widget's styles) — this
   * only switches `absolute` ↔ `fixed`.
   */
  lightboxViewport?: boolean;
  /**
   * Where the widget writes its `data-theme="light|dark"` attribute and
   * injects the operator's theme-token `<style>` block.
   *
   * The React-component embed points these at its **Shadow DOM** — the
   * portal-target element for `themeRoot`, the shadow root itself for
   * `styleRoot` — so the widget's theming is fully self-contained and
   * never mutates (or depends on) the host page's `<html>`. The
   * structural dark-mode rules in `globals.css` (panel glow, header
   * polish) are adopted into the shadow DOM, so they only match when
   * `data-theme` lives inside that same tree.
   *
   * Iframe / web-component embeds leave both undefined and fall back
   * to `document.documentElement` + `document.head`.
   */
  themeRoot?: HTMLElement;
  styleRoot?: ShadowRoot | Document;
  /**
   * Called every time the widget's intended dimensions change. The
   * iframe adapter forwards via `postMessage`; the web-component
   * adapter dispatches a `wexio:resize` `CustomEvent` on the host
   * element so a `ResizeObserver`-style integration on the host can
   * react.
   */
  onResize: (width: number, height: number) => void;
  /**
   * Called when the visitor closes the panel via the close button.
   * Iframe adapter posts to the parent so the loader hides the
   * frame; web-component adapter dispatches a `wexio:close`
   * `CustomEvent` for host-side teardown.
   */
  onClose: () => void;
  /**
   * Reports the operator's resolved `localeStrategy` once the config
   * has loaded — the embed's "phase 2" of locale resolution.
   *
   * The embed wrapper resolves a PROVISIONAL locale at mount (explicit
   * prop/attr, else browser) before the BE strategy is known. Once
   * `useWidgetConfig` has the config it hands the strategy back here so
   * the wrapper can re-resolve via `detectClientLocale(strategy)` — e.g.
   * switch to the host page's `<html lang>` for `WEBSITE`, or to a
   * pinned code. A no-op when the host pinned an explicit locale.
   *
   * Set only by the **embeds** (web-component / react-component). The
   * iframe leaves it undefined: the loader already resolved the strategy
   * and passed `?lang=`, so the server picked the right locale up front.
   */
  onLocaleStrategy?: (strategy: string) => void;
  /**
   * Known-user identity supplied by the host (see `VisitorIdentity`).
   * The web-component (`identify(user)`) and react-component (`user`
   * prop) set this directly. The iframe leaves it undefined and
   * receives identity asynchronously over `postMessage` instead
   * (`useHostVisitorIdentity` bridges that), since the host's data
   * can't cross into the iframe document any other way.
   */
  visitorIdentity?: VisitorIdentity;
  /**
   * Default profile values to pre-fill the prechat form (see
   * `VisitorPrefill`). Set by the embeds directly; the iframe receives
   * it over `postMessage` (`wexio:prefill:v1`), bridged alongside
   * identity in `useHostVisitorData`. Unverified — convenience only.
   */
  visitorPrefill?: VisitorPrefill;
}

/**
 * Default env — assumes iframe + parent window is the host. Matches the
 * pre-existing behaviour so any non-provider path (Storybook stories
 * mounted outside the loader, `next dev` on `/`) still works.
 */
function iframeDefaultEnv(): WidgetEnv {
  const post = (msg: object) => {
    if (typeof window === "undefined") return;
    window.parent?.postMessage(msg, "*");
  };
  return {
    kind: "iframe",
    onResize: (width, height) => post({ type: "wexio:widget:resize:v1", width, height }),
    onClose: () => post({ type: "wexio:widget:close:v1" }),
  };
}

const WidgetEnvContext = createContext<WidgetEnv | null>(null);

export function WidgetEnvProvider({ env, children }: { env: WidgetEnv; children: ReactNode }) {
  return <WidgetEnvContext.Provider value={env}>{children}</WidgetEnvContext.Provider>;
}

/**
 * Read the active embed environment. Falls back to the iframe defaults
 * when no provider is mounted — exactly the behaviour the widget had
 * before this context existed.
 */
export function useWidgetEnv(): WidgetEnv {
  const ctx = useContext(WidgetEnvContext);
  // `useMemo` would be overkill here — `iframeDefaultEnv` is cheap and
  // the consumers store the returned handlers in effect deps that only
  // care about reference equality across a single render.
  return ctx ?? iframeDefaultEnv();
}
