/**
 * Widget configuration shape — mirrors the visitor-facing GraphQL
 * `visitorWebConfig` query plus client-only fields for demo/preview.
 *
 * The widget runs in three modes that share this shape:
 *
 *   - **production**  → bootstrapped from `GET /api/web/config/:publicKey`
 *                       (the one REST endpoint kept for the loader script
 *                       to avoid bundling Apollo into the loader). Rest of
 *                       runtime data via GraphQL.
 *
 *   - **preview**     → operator's dashboard embeds the widget in an
 *                       iframe and posts `wexio:preview-config:v1` messages
 *                       on every theme/feature edit. Hot-swaps tokens
 *                       without a BE round-trip.
 *
 *   - **demo**        → no operator context at all. Built-in mock config
 *                       so the widget renders something on a marketing
 *                       site / first-load preview before the operator
 *                       has picked an integration.
 */

import { assetUrl } from "./asset-url";

export type WidgetMode = "production" | "preview" | "demo";

export type WidgetTab = "home" | "messages" | "help" | "news" | "profile";

export interface WidgetFeatures {
  home: boolean;
  messenger: boolean;
  help: boolean;
  news: boolean;
  /** Operator-gated. When `true`, the bottom-nav surfaces a "Profile" tab
   *  where the visitor can edit their own profile fields + preferences
   *  (language, desktop notifications, theme mode). Defaults to `false` —
   *  the tab is hidden until the operator opts in. */
  profile?: boolean;
}

/* ─── Home-tab block model ───────────────────────────────────────────
 * `WidgetConfig.homeLayout` is an operator-configured ordered list of
 * blocks the Home tab renders top-to-bottom. `null` → the widget falls
 * back to a sensible hardcoded default (see `DEFAULT_HOME_LAYOUT`).
 * Mirrors the BE `homeLayout` JSON shape + the dashboard editor — keep
 * the three in sync. The renderer tolerates unknown `kind`s (skips
 * them) so a newer dashboard can't break an older widget bundle. */

/** Curated icon set for `quick-actions` buttons — channel logos +
 *  common actions. Maps to a bundled icon in the widget. */
export type HomeNamedIcon =
  | "telegram"
  | "whatsapp"
  | "viber"
  | "instagram"
  | "messenger"
  | "discord"
  | "slack"
  | "chat"
  | "email"
  | "phone"
  | "video-call"
  | "help"
  | "book"
  | "bell"
  | "star"
  | "heart"
  | "bookmark"
  | "arrow-right"
  | "lock"
  | "shield"
  | "user"
  | "users";

/** A `quick-actions` button icon — either a curated named icon or an
 *  operator-uploaded image URL. */
export type HomeQuickActionIcon =
  | { kind: "named"; name: HomeNamedIcon }
  | { kind: "media"; url: string };

export interface HomeQuickActionButton {
  /** At least one of `label` / `icon` must be set. */
  label?: string;
  icon?: HomeQuickActionIcon;
  /** Where the tap goes. `open-url` requires `url`. */
  action: "open-messenger" | "open-help" | "open-news" | "open-url";
  url?: string;
  /** Visual weight. Max one `primary` per block. */
  style?: "default" | "primary" | "ghost";
}

/** How a `quick-actions` block lays its buttons out.
 *  - `stacked`  → one full-width row per button (default; best for
 *                 verbose labels + primary CTAs).
 *  - `inline`   → up to 4 icon-only square tiles in a row (best for
 *                 channel-switchers — WhatsApp / Telegram / Instagram).
 *                 Labels become tooltips; long labels are clamped. */
export type HomeQuickActionLayout = "stacked" | "inline";

export interface HomeHelpSuggestionsConfig {
  mode: "popular" | "recent" | "category" | "manual";
  /** 3–8. */
  maxItems: number;
  categoryId?: string;
  articleIds?: string[];
}

export type HomeBlock =
  | {
      kind: "quick-actions";
      buttons: HomeQuickActionButton[];
      /** Defaults to `"stacked"` when omitted. */
      layout?: HomeQuickActionLayout;
    }
  | {
      kind: "help-search";
      placeholder?: string;
      suggestions: HomeHelpSuggestionsConfig;
    }
  | { kind: "pinned-articles"; articleIds: string[]; title?: string }
  | { kind: "news-preview"; maxItems?: number; title?: string }
  | {
      kind: "team-status";
      showResponseTime: boolean;
      showOperatorAvatars: boolean;
    }
  | { kind: "divider" }
  | { kind: "rich-text"; markdown: string }
  /** CTA card — title + subtitle + operator avatar stack + chevron. Tap
   *  opens the messenger. Visual style of the demo "Ask a question"
   *  card; copy is operator-configurable. */
  | {
      kind: "ask-question";
      title?: string;
      subtitle?: string;
      /** Tap target. Defaults to `"open-messenger"`. */
      action?: "open-messenger" | "open-help" | "open-news";
    }
  /** Recent-message card — header strip + the latest inbound message
   *  for the visitor. Live mode hides when the visitor has no chat
   *  history; demo mode shows a bundled sample. */
  | { kind: "recent-message"; title?: string }
  /** Single hero card for a featured **news post**. Operator picks the
   *  post by id in the dashboard; the widget hydrates title + excerpt
   *  + cover image from the BE (`visitorNewsPost({ id })`). Tap drills into
   *  the news article view. `ctaLabel` overrides the footer copy
   *  ("See the launch agenda" by default). When `newsId` is unset or
   *  the post can't be resolved the card paints a gradient placeholder
   *  so the home tab never has a blank rectangle. */
  | {
      kind: "featured-article";
      newsId?: string;
      ctaLabel?: string;
    };

export type HomeBlockKind = HomeBlock["kind"];

/**
 * A complete palette of brandable colour tokens — designer-friendly
 * names (`background`, `surface`, `text`, ...) that mirror the BE's
 * `WebIntegrationThemePalette` shape exactly. The widget translates
 * these into the internal `--wx-*` CSS variables at apply time
 * (see `applyThemeOverrides` in `use-widget-config.ts`).
 *
 * Every field optional — widget falls back to the bundled defaults
 * in `globals.css` for any token the operator hasn't set.
 */
export interface WidgetThemePalette {
  // Surfaces
  background?: string;
  surface?: string;
  surfaceElevated?: string;
  // Text
  text?: string;
  textMuted?: string;
  textSubtle?: string;
  // Borders
  border?: string;
  borderStrong?: string;
  // Brand
  primary?: string;
  primaryHover?: string;
  primaryForeground?: string;
  // Launcher
  launcherBackground?: string;
  launcherForeground?: string;
  // Status
  success?: string;
  danger?: string;
}

export interface WidgetThemeRadii {
  sm?: number;
  md?: number;
  lg?: number;
  xl?: number;
}

/** Anchor corner for the floating launcher + panel on the host page.
 *  Mirrors the BE's `LauncherPosition` enum. Defaults to bottom-right. */
export type LauncherPosition = "RIGHT_BOTTOM" | "LEFT_BOTTOM";

export interface WidgetTheme {
  /** Light-mode palette. Active when `useThemeMode()` resolves to
   *  `'light'`. */
  light?: WidgetThemePalette;
  /** Dark-mode palette. Active when `useThemeMode()` resolves to
   *  `'dark'`. */
  dark?: WidgetThemePalette;
  /** Radii are theme-invariant — same values apply in both modes. */
  radii?: WidgetThemeRadii;
  /** Which corner the launcher + panel anchor to. Theme-invariant;
   *  lives in `theme` to mirror the BE's `WebIntegrationTheme` shape. */
  launcherPosition?: LauncherPosition;
  /** Full CSS `font-family` stack applied to the whole widget.
   *  Theme-invariant. When unset the widget keeps its bundled Geist
   *  default. Mirrors the BE's `WebIntegrationTheme.fontFamily`. */
  fontFamily?: string;
}

export type PrechatFieldKind = "NAME" | "EMAIL" | "PHONE" | "CUSTOM_TEXT";

export interface WidgetPrechatField {
  /** Drives the input type + default label/validator. `CUSTOM_TEXT`
   *  is the open-text catch-all (e.g. "Order number"). */
  kind: PrechatFieldKind;
  /** Stable identifier the BE uses on submit. Operators set this
   *  when designing the form; `[a-z0-9_]{1,32}` per BE validator. */
  key: string;
  /** Operator-supplied label. Empty string = render the i18n default
   *  for `kind` (e.g. "Email" / "Email"). */
  label: string;
  required: boolean;
}

export interface WidgetPrechatForm {
  /** When `false`, the form never renders even if `fields` is populated. */
  enabled: boolean;
  fields: WidgetPrechatField[];
}

export interface WidgetSounds {
  /** Operator-level global mute. Visitor `wexio:sound-muted` localStorage
   *  overrides this — visitors always win. */
  enabled: boolean;
  /**
   * Sound played when an inbound (operator/bot/AI) message arrives.
   * Either a preset id (`"wx-nt_3"`, picks `public/sounds/wx-nt_3.wav`)
   * OR a fully-qualified URL pointing at an operator-uploaded asset.
   * `null` = silent for this direction.
   */
  inboundSoundId: string | null;
  /** Same shape; played when the visitor's outbound send acknowledges. */
  outboundSoundId: string | null;
  /** 0.0 (silent) … 1.0 (full), clamped. */
  volume: number;
}

export interface WidgetBranding {
  /**
   * Hide the in-widget "Powered by Wexio" badge. Default `false` —
   * free + standard tiers MUST show the badge; only enterprise /
   * white-label plans can set this to `true`. The BE enforces the
   * plan gate on save; the widget treats `true` as "operator paid
   * for white-label" and trusts it without re-checking.
   *
   * The badge is the in-widget visual surface. The separate
   * SEO-backlink injection on the host page (loader script) is its
   * own toggle — operators who hide one don't automatically hide
   * the other.
   */
  hidden: boolean;
}

/**
 * Widget UI-language strategy (operator-configured on the BE):
 *   - `"AUTO"`    — follow the visitor's browser (`navigator.language`).
 *   - `"WEBSITE"` — follow the host page's `<html lang>`.
 *   - `"DEFAULT"` — pin every visitor to the integration's `defaultLocale`.
 */
export type WidgetLocaleStrategy = "AUTO" | "WEBSITE" | "DEFAULT";

/**
 * Visitor-auth configuration (operator-controlled). Which sign-in methods
 * the widget offers, and whether messaging is gated behind a verified
 * identity. Extensible — new methods slot in alongside `google`/`passkey`.
 */
export interface WidgetSecurity {
  /** When `true`, the widget shows the sign-in panel INSTEAD of the
   *  message/voice composer until the visitor is verified (`anon:false`). */
  requireAuth: boolean;
  /** "Sign in with Google" via Google Identity Services. The widget
   *  runs GIS directly in-panel using `clientId` (a PUBLIC OAuth
   *  identifier — same one the operator already embeds on their
   *  main-site Google login). The resulting `id_token` rides
   *  `startIdentifiedVisitor`; the BE verifies `aud === clientId`
   *  server-side via `WebAuthProofService.verifyGoogleIdToken`.
   *  Rendered only when `enabled` AND `clientId` is set. */
  google: { enabled: boolean; clientId: string | null };
  /** Passkey (WebAuthn) sign-in — runs entirely in the widget. */
  passkey: { enabled: boolean };
}

/**
 * Host-injectable shape of `WidgetSecurity` — every field optional,
 * each defaults to the BE value when the host omits it. BE remains the
 * source of truth for actual gating (enforces `requireAuth`
 * server-side; verifies Google `id_token.aud` server-side regardless
 * of where the token was minted). Host-supplied values here are UI /
 * test-harness conveniences.
 */
export interface InjectableWidgetSecurity {
  /** Force-show the sign-in gate even when the BE gate fetch is
   *  unavailable (e.g. the inject test harness without a publicKey).
   *  BE-enforced server-side regardless. */
  requireAuth?: boolean;
  /** Host can flip whether Google sign-in is offered — but `clientId`
   *  is deliberately NOT injectable. The widget always reads the
   *  Google `clientId` from the BE config (`/api/web/config`); hosts
   *  must not bypass that to avoid mismatches with the BE's
   *  audience check. */
  google?: { enabled?: boolean };
  passkey?: { enabled?: boolean };
}

export interface WidgetConfig {
  // NOTE: no `integrationId` / `name` / `publicKey` — those are the
  // integration's internal admin fields, BE-resolved from the publicKey
  // and never returned to the visitor. The widget keys per-integration
  // state off the `publicKey` it already holds, and the visitor-facing
  // name is `messenger.title`.
  status: "active" | "disabled" | "plan_blocked";
  defaultTab: WidgetTab;
  /** How the widget picks the visitor's UI language. `"AUTO"` follows
   *  the browser (`navigator.language`); `"WEBSITE"` follows the host
   *  page's `<html lang>`; `"DEFAULT"` pins to `defaultLocale`.
   *  Resolved by `detectClientLocale` (embeds) / the loader (iframe).
   *  Defaults to `"AUTO"` for legacy configs. */
  localeStrategy: WidgetLocaleStrategy;
  /** The integration's canonical / fallback language (BCP-47). Used to
   *  resolve `localeStrategy: "DEFAULT"`, and as the content fallback.
   *  Defaults to `"en"`. */
  defaultLocale: string;
  /** Visitor-auth config — which sign-in methods the widget offers and
   *  whether messaging is gated behind a verified identity. */
  security: WidgetSecurity;
  features: WidgetFeatures;
  theme: WidgetTheme | null;
  themeMode: "light" | "dark" | "auto";
  /** Operator avatars surfaced in the header stack (max 3). */
  operatorAvatars: { src: string; alt: string }[];
  /** Organisation logo — per-mode URLs (already flattened from the
   *  BE's Media refs by `fetchWebConfig`). The shell resolves the
   *  active URL by theme mode; when both are `null` the header
   *  renders the framed Wexio fallback mark. `null` for the whole
   *  object = operator never uploaded a logo. */
  organizationLogo: { light: string | null; dark: string | null } | null;
  /** Greeting shown on the Home tab — operator-configurable copy. */
  greeting: {
    headline: string;
    subheadline: string;
  };
  /** Operator-configured Home-tab block layout, rendered top-to-bottom.
   *  `null` → the widget falls back to `DEFAULT_HOME_LAYOUT`. */
  homeLayout: HomeBlock[] | null;
  /** Pre-chat form configuration. `null` (or `enabled: false`) means
   *  visitors send their first message straight from the composer
   *  with no gate. */
  prechatForm: WidgetPrechatForm | null;
  /** Branding controls — `null` for the implicit default (badge shown). */
  branding: WidgetBranding | null;
  /** Sound preferences — `null` for the implicit default (presets + 0.5 volume). */
  sounds: WidgetSounds | null;
  /** Messenger-tab configuration — operator copy for the chat surface
   *  (title, description, pre-populated bot messages), AI assistant
   *  avatar override, slash-command quick-tap chips, and display
   *  toggles for the related-news / related-help / reaction-count
   *  blocks. `null` → all fields fall back to widget defaults. */
  messenger: WidgetMessengerConfig | null;
}

/**
 * The subset of `WidgetConfig` a HOST may inject via the `config` prop /
 * `window.wexioSettings.config` (to skip the heavy bootstrap fetch). It
 * EXCLUDES the plan / restriction gate (`branding`, `status`) — those are
 * BE-owned, fetched authoritatively by publicKey (the lite `?view=gate`
 * config) so a host can't fake white-label removal or the plan gate.
 *
 * (`integrationId` / `name` / `publicKey` / `allowedOrigins` aren't part of
 * `WidgetConfig` at all — they're the integration's internal admin fields,
 * never returned to the visitor; the widget keys per-integration state off
 * the `publicKey` it already holds and uses `messenger.title` for display.)
 *
 * So a host passes ONLY presentation: theme / messenger / features /
 * homeLayout / greeting / prechat / sounds / security methods / locales.
 */
export type InjectableWidgetConfig = Omit<WidgetConfig, "branding" | "status" | "security"> & {
  /** Sign-in methods — host can only flip `enabled` per method.
   *  `clientId` and `requireAuth` are BE-sourced (see
   *  `InjectableWidgetSecurity`). Optional so a host that doesn't
   *  care about auth gating can omit it entirely. */
  security?: InjectableWidgetSecurity;
};

/**
 * Operator-configured pre-populated messages in the messenger tab.
 *
 * `TEXT` was removed in the WEB_VISITOR_VISIT flow-trigger landing —
 * proactive bot bubbles now arrive via SSE from the flow runner, not
 * as static config. Only the chrome affordances remain here:
 *
 *   - `HINT`   — italic tip card (e.g. "Try `/start`").
 *   - `SYSTEM` — centred status pill (e.g. "We're back online").
 */
export type WidgetMessengerMessageKind = "HINT" | "SYSTEM";

export interface WidgetMessengerMessage {
  kind: WidgetMessengerMessageKind;
  text: string;
}

export interface WidgetMessengerConfig {
  /** Header title — falls back to the i18n default `"Send us a message"`
   *  when null / empty. ≤ 120 chars on the BE. */
  title: string | null;
  /** Sub-header description — falls back to the i18n default when null
   *  / empty. ≤ 500 chars on the BE. */
  description: string | null;
  /** Avatar URL surfaced on AI / bot bubbles. The BE flattens the
   *  Media `_id` to a CDN URL before sending the config; this is
   *  already a fetchable string by the time it reaches the widget.
   *  `null` → AI bubbles render WITHOUT an avatar (no Wexio mark
   *  fallback), so the operator explicitly opts in to surfacing a
   *  bot identity. */
  aiAssistantAvatar: string | null;
  /** Slash-command quick-tap chips surfaced in the composer's
   *  commands dropdown. Each entry is the literal text the visitor
   *  sends on tap (e.g. `"/start"`). Empty array → the commands
   *  dropdown trigger is hidden entirely. Capped at 20 by the BE,
   *  each `^/[a-zA-Z0-9_-]{1,32}$`. */
  commands: string[];
  /** Pre-populated messages that paint at the top of the thread
   *  before any real visitor / operator turn. Render styles depend
   *  on `kind`:
   *    - `TEXT`   — normal bot bubble (treats sender as AI).
   *    - `HINT`   — dim italic affordance pill.
   *    - `SYSTEM` — centred system row (matches runtime
   *                 `MessageType.SYSTEM`).
   *  Capped at 10 by the BE. */
  messages: WidgetMessengerMessage[];
  /** Surface the "Related news" affordance below the welcome
   *  message run. */
  showRelatedNews: boolean;
  /** Surface the "Related help articles" affordance below the
   *  welcome message run. */
  showRelatedHelpArticles: boolean;
  /** Render aggregate reaction counts under each bot message. */
  showReactionCounts: boolean;
}

